  "phbtulDisguiseKi": {
    "name": "Verkleidungsausrüstung",
    "description": "<p>Dieser Beutel mit Schminke, Haarfärbemitteln und kleinen Requisiten lässt dich Verkleidungen entwerfen, die dein Äußeres verändern.</p>\n<p>Bist du im Umgang mit diesem Werkzeug geübt, darfst du deinen Übungsbonus auf alle Attributs- und Fertigkeitswürfe addieren, wenn du dich äußerlich verkleidest.</p>"
  },
  "phbtulForgeryKit": {
    "name": "Fälscherausrüstung",
    "description": "<p>Dieser kleine Kasten enthält ein breites Spektrum an Papieren und Pergamenten, Schreibwerkzeugen und Tinten, Siegeln und Siegelwachs, Gold- und Silberplättchen sowie andere Ausrüstung, die notwendig ist, um überzeugende Fälschungen von tatsächlichen Dokumenten zu erschaffen. Bist du im Umgang mit diesem Werkzeug geübt, darfst du deinen Übungsbonus auf alle Attributs- und Fertigkeitswürfe addieren, die mit dem Fälschen von Dokumenten in Verbindung stehen.</p>"
  },
  "phbtulHerbalismK": {
    "name": "Kräuterkundeausrüstung",
    "description": "<p>Diese Ausrüstung enthält eine Auswahl von Instrumenten wie Pinzetten, Mörser und Stößel sowie Phiolen und Beutelchen, die von Kräuterkundigen verwendet werden, um Salben und Tränke herzustellen. Bist du im Umgang mit diesem Werkzeug geübt, darfst du deinen Übungsbonus auf alle Attributs- und Fertigkeitswürfe addieren, die mit dem Anwenden und Identifizieren von Kräutern sowie dem Herstellen von Gegengiften und Heiltränken in Verbindung stehen.</p>"
  },
  "phbtulNavigators": {
    "name": "Navigationswerkzeuge",
    "description": "<p>Diese Werkzeuge werden für die Navigation auf See verwendet.</p>\n<p>Übung im Umgang mit Navigationswerkzeug, ermöglicht es dir den Kurs eines Schiffes zu bestimmen und Navigationskarten zu folgen.</p>\n<p>Außerdem, erlauben dir diese Instrumente deinen Übungsbonus auf jeden Fertigkeitswurf zu addieren, den du machst, um zu verhindern, dass du auf See verloren gehen.</p>"
  },
  "phbtulPoisonersK": {
    "name": "Giftmischerausrüstung",
    "description": "<p>Die Giftmischerausrüstung enthält Phiolen, Chemikalien und andere Gegenstände, die zum Herstellen von Giften benötigt werden. Bist du im Umgang mit diesem Werkzeug geübt, darfst du deinen Übungsbonus auf alle Attributs- und Fertigkeitswürfe addieren, die mit der Herstellung und Anwendung von Giften in Verbindung stehen.</p>"
  },
  "phbtulThievesToo": {
    "name": "Diebeswerkzeug",
    "description": "<p>Dieser Satz Werkzeuge enthält eine kleine Feile, verschiedene Dietriche, einen kleinen Spiegel mit Handgriff, unterschiedliche Scheren mit dünnen Schneiden und einige Pinzetten. Bist du im Umgang mit diesem Werkzeug geübt, darfst du deinen Übungsbonus auf alle Attributs- und Fertigkeitswürfe addieren, die mit dem Entschärfen von Fallen oder dem Öffnen von Schlössern in Verbindung stehen.</p>"
  },
  "phbmusBagpipes00": {
    "name": "Dudelsack",
    "description": "<p>Ein Dudelsack, um bei Ihrem Publikum Ehrfurcht, Staunen oder Angst zu wecken.</p>\n<p>Wenn Sie ein bestimmtes Musikinstrument beherrschen, können Sie Ihren Übungsbonus zu allen Fertigkeitswürfen für das Musizieren mit dem Instrument hinzufügen. Ein Barde kann ein Musikinstrument als Zauberfokus verwenden. Jede Art von Musikinstrument erfordert eine eigene Befähigung.</p>"
  },
  "phbmusDrum000000": {
    "name": "Trommel",
    "description": "<p>Eine Trommel, egal welcher Art, um Ehrfurcht, Erstaunen oder Furcht in Ihrem Publikum hervorzurufen.</p>\n<p>Bist du im Umgang mit einem Musikinstrument geübt, darfst du deinen Übungsbonus auf alle Attributs- und Fertigkeitswürfe addieren, die mit dem Spielen des Instruments in Verbindung stehen. Ein Barde kann sein Instrument als Zauberfokus, anstelle einer Materialkomponente, für die keine Kosten aufgeführt sind, verwenden. Jedes Musikinstrument benötigt seine eigene Übung.</p>"
  },
