  "KZUoiZrigDbovEu7": {
    "name": "Blendlaterne",
    "description": "<p>Eine Blendlaterne wirft einen 18 m langen Kegel hellen Lichts, der weitere 18 m in dämmriges Licht taucht. Einmal entfacht, brennt die Laterne mit einem Fläschchen Öl (0,5l) für 6 Stunden.</p>"
  },
